// 5 LEDs flashing in sequence with servo rotation

#include <Servo.h>

const int LED_RED = 9;
const int LED_YELLOW = 10;
const int LED_GREEN = 11;
const int LED_BLUE = 12;
const int LED_PURPLE = 13;
const int SERVO_PIN = 6;

const int DELAY_MS = 300;

Servo servo;

void setup() {
  pinMode(LED_RED, OUTPUT);
  pinMode(LED_YELLOW, OUTPUT);
  pinMode(LED_GREEN, OUTPUT);
  pinMode(LED_BLUE, OUTPUT);
  pinMode(LED_PURPLE, OUTPUT);

  servo.attach(SERVO_PIN);
  servo.write(0); // Start at 0 degrees
}

void loop() {
  // Flash each LED in sequence and rotate servo

  // Red LED - 0 degrees
  digitalWrite(LED_RED, HIGH);
  servo.write(0);
  delay(DELAY_MS);
  digitalWrite(LED_RED, LOW);

  // Yellow LED - 45 degrees
  digitalWrite(LED_YELLOW, HIGH);
  servo.write(45);
  delay(DELAY_MS);
  digitalWrite(LED_YELLOW, LOW);

  // Green LED - 90 degrees
  digitalWrite(LED_GREEN, HIGH);
  servo.write(90);
  delay(DELAY_MS);
  digitalWrite(LED_GREEN, LOW);

  // Blue LED - 135 degrees
  digitalWrite(LED_BLUE, HIGH);
  servo.write(135);
  delay(DELAY_MS);
  digitalWrite(LED_BLUE, LOW);

  // Purple LED - 180 degrees
  digitalWrite(LED_PURPLE, HIGH);
  servo.write(180);
  delay(DELAY_MS);
  digitalWrite(LED_PURPLE, LOW);

  delay(100); // Pause before next cycle

  // Rotate back to 0 degrees
  servo.write(0);
  delay(500); // Extra pause for return
}

